// ──────────────────────────── Selectors ───────────────────────────────

export function cityFactsFor(
  citySlug: string,
  birthYear: number,
  windowYears = 90,
): CityFact[] {
  return CITY_FACTS.filter(
    (f) =>
      f.city === citySlug &&
      f.year >= birthYear - 5 && // also include a few "right before they were born"
      f.year <= birthYear + windowYears,
  ).sort((a, b) => a.year - b.year);
}
